protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 disallows non-constant expressions in HasData (e.g. DateTime.UtcNow).
    // Use a fixed value so seed data is deterministic and won't generate new migrations each run.
    modelBuilder.Entity<Order>().HasData(
        new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
}

arguments.old_str:
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        using var transaction = db.Database.BeginTransaction();
        db.Database.Migrate();
        transaction.Commit();
    });
}

arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 throws if Migrate() is called inside a user-managed transaction.
    // Migrations manage their own transactions internally.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

